worktree_state.content:
{
  "$comment": [
    "E-Menum Theme Manifest",
    "This is an example/reference theme for developers creating custom themes.",
    "Copy this entire folder and modify to create your own theme."
  ],

  "name": "example-theme",
  "displayName": "Example Reference Theme",
  "version": "1.0.0",
  "description": "A minimal, well-documented example theme for developers. Use this as a starting point for creating custom themes.",
  "author": "E-Menum",
  "type": "product",
  "enabled": false,
  "priority": 200,

  "layouts": {
    "default": "layouts/default.ejs"
  },

  "components": {
    "header": "components/header.ejs",
    "footer": "components/footer.ejs",
    "menu-item": "components/menu-item.ejs"
  },

  "partials": {},

  "styles": {
    "main": "styles/main.css"
  },

  "assets": {
    "logo": {
      "light": "/images/logo-light.svg",
      "dark": "/images/logo-dark.svg"
    },
    "favicon": "/favicon.ico",
    "placeholder": "/images/product-placeholder.svg"
  },

  "features": {
    "darkMode": true,
    "rtlSupport": false,
    "responsive": true,
    "offlineSupport": false,
    "pwa": false,
    "accessibility": {
      "wcagLevel": "AA",
      "highContrast": true,
      "reducedMotion": true,
      "touchTargetSize": "48px"
    }
  },

  "navigation": {
    "header": {
      "fixed": true,
      "showLogo": true,
      "showSearch": false,
      "showCart": true
    },
    "footer": {
      "showBranding": true,
      "showSocialLinks": false
    }
  },

  "colors": {
    "primary": "#6366f1",
    "primaryLight": "#818cf8",
    "primaryDark": "#4f46e5",
    "secondary": "#ec4899",
    "accent": "#10b981"
  },

  "cart": {
    "position": "bottom-fixed",
    "animation": "slide-up",
    "showItemCount": true,
    "showTotal": true
  },

  "product": {
    "imageAspectRatio": "4:3",
    "showPrice": true,
    "showDescription": true,
    "showAllergens": true,
    "showBadges": true
  },

  "breakpoints": {
    "sm": "640px",
    "md": "768px",
    "lg": "1024px",
    "xl": "1280px"
  },

  "dependencies": {
    "css": [],
    "js": ["alpinejs"],
    "icons": ["phosphor-icons"]
  }
}
